159→void ALFPTurnManager::ProcessNextEnemyPlan()
160→{
161→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
162→    {
163→        // 所有敌人规划完毕
164→        EndEnemyPlanningPhase();
165→        return;
166→    }
167→
168→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
169→
170→    // 跳过死亡单位
171→    if (!Enemy || !Enemy->IsAlive())
172→    {
173→        CurrentPlanningEnemyIndex++;
